var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"바다에서 몰려오는 놈들은 처리했어.","JPN":"海から押し寄せてくるやつらは片付けたぞ。","ENG":"Handled the ones coming in from the sea.","TWN":"從海上靠近的都解決了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"야, 이제 됐지?","JPN":"おい、これでいいだろ？","ENG":"Hey, we're done here, right?","TWN":"喂，這樣可以了吧？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"이 사람들 대피시키든 말든 결정하는 건 네가 해.","JPN":"ここの人たちを避難させるかどうかはお前が決めろ。","ENG":"Whether you evacuate these people or not, that's your call.","TWN":"妳自己決定這些人要不要撤走。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그 많은 침식체들을…….","JPN":"あんなに多かった侵食体を……","ENG":"All those C.O.s...","TWN":"那麼多侵蝕體……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"저 정도 되는 카운터를 정보부인 내가 몰랐다고?","JPN":"あれほどのカウンターを、情報部の私が知らなかったなんてあり得る？","ENG":"And I, an intelligence agent, didn't know a Counter like that existed?","TWN":"在情報部的我居然不知道有這種制裁者？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"프론트 베이… 도대체 무슨 괴물을 숨겨둔 거야?","JPN":"フロントベイ……なんて化け物を隠していたの？","ENG":"Front Bay... just what kind of monster were you hiding?","TWN":"前灣……究竟藏了什麼怪物啊？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"모네네 고향을 지켜줘서 감사함다!","JPN":"モネの故郷を守ってくれてありがとうっす！","ENG":"Thank you for protecting Mone's hometown!","TWN":"謝謝你們守住莫妮的故鄉！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L16_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"검은 범람을 막지 못하면 이곳도 언젠간 물에 잠기거나 침식체 밭이 될 거야.","JPN":"黒い氾濫を食い止められなかったら、ここもいつかは水に沈むか侵食体の巣窟になる。","ENG":"If we don't stop the Black Flood, this place will end up underwater, or overrun with C.O.s, eventually.","TWN":"如果無法阻止黑色洪災，這裡遲早也會被淹沒或變成侵蝕體巢穴。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"지금이라도 사람들을 모아서 떠나라고 해.","JPN":"すぐにでもみんなを集めて、ここから離れたほうが身のためだな。","ENG":"Tell everyone to gather their things and leave while they can.","TWN":"現在帶著大家離開吧。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"여기도 리코리스 같은 분이 계셨군요.","JPN":"こちらにもリコリスのようなお方が。","ENG":"So there's someone like Lycoris here too.","TWN":"原來這裡也有像莉克麗絲這樣的人啊。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"저희는 이곳을 지키기 위해 남은 겁니다.","JPN":"私たちはここを守るために残ったのです。","ENG":"We stayed because we want to protect this island.","TWN":"我們留下是為了保護這座島。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"많은 사람들의 추억이 서린 이 섬을요.","JPN":"多くの人の思い出が詰まったこの島を。","ENG":"An island full of people's memories.","TWN":"這裡承載著許多人的回憶。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"모네는 이 섬 안 떠날 검다!","JPN":"モネは島から出ないっす！","ENG":"Mone will not leave this island!","TWN":"莫妮不會離開這座島！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"부모님도, 다른 사람들도 마찬가지임다!","JPN":"両親も、他の人たちも同じっす！","ENG":"My parents won't, and neither will anyone else!","TWN":"我的父母和其他人都一樣！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"젠장, 지금이 무슨 소꿉장난 하러 온 줄 알아?!","JPN":"くそ、おままごとしに来たんじゃないんだぞ！","ENG":"Damn it. What do you think this is, playtime?!","TWN":"可惡，你們以為現在在玩扮家家酒嗎？！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"야, 깡통. 이런 건 관리국에서 강제로 데려가고 그런 거 없어?","JPN":"おい、ポンコツ。こういうの管理局で強制的に連れて行ったりとかできないのか？","ENG":"Hey, tin can. Doesn't the Administration ever just haul people out by force?","TWN":"喂，鐵桶，這種時候管理局不能強制撤離嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"권고는 할 수 있지만, 응하는 건 개인의 선택이에요.","JPN":"勧告はできますが、それに応じるのは個人の選択です。","ENG":"We can recommend evacuation, but whether they accept is their choice.","TWN":"可以勸告，但是否接受是個人選擇。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L30_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"게다가 이토록 확고한 분들이라면…….","JPN":"それに、これほどに意志の固い方々なら……","ENG":"And if their resolve is this firm, then...","TWN":"而且看他們這麼堅定，應該勸不了……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"자, 잠깐만요.","JPN":"ま、待ってください。","ENG":"W-wait.","TWN":"等、等一下。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"근방에서 차원 계면 손상이 감지되고 있어요!","JPN":"近くで次元界面の損傷が感知されています！","ENG":"Dimension surface damage detected nearby!","TWN":"附近偵測到次元界面受損！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"뭐라고?","JPN":"何だと？","ENG":"What?","TWN":"什麼？！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"차, 차원 계면을 찢고 침식체가……?","JPN":"じ、次元界面を破って侵食体が……？","ENG":"Th-the C.O. is tearing through the dimension surface?!","TWN":"侵、侵蝕體破壞次元界面……？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"위험해요! 여러분들은 서둘러 섬주민들을 피신시켜주세요!","JPN":"危険です！　皆さんは急いで島の住民を避難させてください！","ENG":"It's dangerous! Please hurry and get the islanders to safety!","TWN":"危險！大家快帶島民撤離！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"젠장, 어마어마하게 크잖아……!","JPN":"くそ、とんでもなくデカい……！","ENG":"Damn it, that thing's huge...!","TWN":"可惡，好大一隻……！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"야, 깡통! 출력 제한 풀어!","JPN":"おい、ポンコツ！　出力制限を解除しろ！","ENG":"Hey, tin can! Take off the output limiter!","TWN":"喂，鐵桶！解除輸出限制！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"하, 하지만…….","JPN":"で、ですが……","ENG":"B-but...","TWN":"但、但是……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그럼 이대로 사이좋게 다 뒈지자는 거야?!","JPN":"じゃあこのままみんな仲良くあの世に行くか！？","ENG":"So you'd rather we all just die together?!","TWN":"不然要大家一起送死嗎？！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That's...","TWN":"那個……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"이런… 놈이 공격한다!","JPN":"しまった……やつが攻撃してくる！","ENG":"Oh no... it's attacking!","TWN":"糟了，它攻擊了！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"음……?","JPN":"うん……？","ENG":"Hmm...?","TWN":"嗯……？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"저 거대한 녀석이… 잠깐이지만 멈췄어.","JPN":"あの巨体が……一瞬だけど止まった。","ENG":"That giant thing... stopped. Just for a moment.","TWN":"那巨大的傢伙……暫停了一下。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"대체 어떻게…….","JPN":"いったいどうやって……","ENG":"How...?","TWN":"到底怎麼回事……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEADER_MAID_NULL_QM","text":{"KOREA":"침식체의 갑피는 단단하지만, 그 사이에는 총알 하나가 들어갈 정도의 틈이 있습니다.","JPN":"侵食体の甲皮は硬いですが、その間には銃弾1個分程の隙間があるのです。","ENG":"A C.O.'s armor is tough, but there are small gaps just wide enough for a single bullet.","TWN":"侵蝕體的殼雖然堅硬，但在那之間有容得下一發子彈的小縫。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEADER_MAID_NULL_QM","text":{"KOREA":"그 부분만 노릴 수 있다면, 잠시 동안이나마 시간을 버는 것이 가능하죠.","JPN":"そこをピンポイントで狙えるのなら、少しだけ時間稼ぎが可能です。","ENG":"If you can hit only that point, you can buy a brief window of time.","TWN":"只要瞄準那裡，就能爭取一點時間。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"저희가 청소하지 못하는 침식체를 처리해 주신 점, 메이드를 대표해 감사드립니다.","JPN":"私たちが掃除できない侵食体を処理してくださったこと、メイドを代表して感謝いたします。","ENG":"On behalf of the maids, thank you for dealing with a C.O. we could not clean up ourselves.","TWN":"謝謝妳幫我們清理那些我們無法處理的侵蝕體。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"단 한발로… 침식체의 약점 부위를 정확히 쏘는 사람이 할 말은 아닌 것 같은데.","JPN":"たった一発で……侵食体の弱点を正確に狙える人が言うことじゃないと思うけど。","ENG":"Says the person who just hit its weak point... with a single shot.","TWN":"能用一發子彈精準命中侵蝕體弱點的人，好像沒資格說這話吧？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"당신 도대체 뭐야?","JPN":"お前……いったい何者なんだ？","ENG":"Who are you?","TWN":"妳到底是誰？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"저는 플로라 메이드 서비스의 메이드장, 베로니카라고 합니다.","JPN":"私はフローラメイドサービスのメイド長、ベロニカと申します。","ENG":"I am Veronica, Chief Maid of Flora Maid Service.","TWN":"我是芙蘿拉女僕服務公司的女僕長，貝洛妮卡。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"요양 중인 몸으로 손님을 맞이하게 되어 송구스럽습니다.","JPN":"療養中の身でお客様をお迎えすることとなり、誠に申し訳ございません。","ENG":"Forgive me for greeting you while still recovering.","TWN":"以療養中的身體迎接客人實在失禮，"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"부디 넓은 아량으로 이해해 주시길.","JPN":"どうぞご容赦ください。","ENG":"I ask for your gracious understanding.","TWN":"還請各位見諒。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"메이드장님? 아직 이곳은 위험합니다!","JPN":"メイド長？　まだここは危険です！","ENG":"Chief Maid? This area is still dangerous!","TWN":"女僕長？！這裡還很危險！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L23_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"괜찮아요, 릴리.","JPN":"大丈夫です、リリー。","ENG":"It's fine, Lily.","TWN":"沒關係的，莉莉。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"여러분이 고생하고 계시는데 메이드장인 제가 가만히 있을 수는 없죠.","JPN":"皆さんが苦労しておられるのに、メイド長である私がじっとしているわけにはいきません。","ENG":"I can't just sit still while everyone else is struggling.","TWN":"大家這麼辛苦，身為女僕長的我總不能袖手旁觀。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그리고……","JPN":"それに……","ENG":"And...","TWN":"還有……"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"두 분, 잠시 따라와 주시겠습니까?","JPN":"お二人とも、私に付いて来ていただけますか？","ENG":"Would you two follow me for a moment?","TWN":"兩位，可以跟我來一下嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"마을 분들께서 여러분에게 감사 인사를 전하고 싶다 하십니다.","JPN":"村の方たちが皆さんにお礼をしたいそうです。","ENG":"The villagers wish to express their gratitude.","TWN":"村民們想親自向你們道謝。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"뭐해요, 안 가고?","JPN":"何しているんです？　行かないのですか？","ENG":"What are you doing? Aren't you going?","TWN":"幹嘛不去？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L33_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"우리 시간 없는 거 아니었어?","JPN":"あたしたち、時間がないんじゃなかったのか？","ENG":"Aren't we short on time?","TWN":"我們不是沒時間嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"지금 이 순간에도 프론트 베이 사람들은 침식체들에게…….","JPN":"こうしている間にも、フロントベイのみんなが侵食体に……","ENG":"Even now, the people of Front Bay are being attacked by C.O.s–","TWN":"現在這一刻，前灣的人也還在和侵蝕體拚命……"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"제가 처음에 그런 걱정을 했던 건 사실이에요.","JPN":"確かに最初はそういった心配をしていました。","ENG":"It's true that I worried about that at first.","TWN":"我一開始也有同樣的擔憂。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"하지만 프론트 베이는 당신이 없더라도 최선을 다해 싸워줄 겁니다.","JPN":"ですが、フロントベイはあなたがいなくても最善を尽くして戦ってくれるはずです。","ENG":"But Front Bay will fight with everything they have, even without you.","TWN":"但前灣的人即使沒有你，也會全力戰鬥。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"해적들은 고향을 지키기 위해서, 헌터들은 맡은 임무를 위해.","JPN":"海賊たちは故郷を守るために、ハンターたちは任務を果たすために。","ENG":"The pirates to protect their home. The hunters to fulfill their mission.","TWN":"海盜們為了自己的故鄉、獵人們為了自己的任務，"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"관리국은 그곳의 모든 사람을 지키기 위해 노력하겠죠.","JPN":"そして、管理局はそこにいるすべての人を守るために努力するはずです。","ENG":"And the Administration to safeguard everyone there.","TWN":"管理局也會為了保護所有人而努力。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그러니 따라가세요.","JPN":"ですから、行ってください。","ENG":"So go on.","TWN":"所以跟她走吧。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"간다고 손해 볼 일은 없을 테니까요.","JPN":"行っても損はしないと思いますよ。","ENG":"You won't lose anything by doing so.","TWN":"去一趟不會吃虧的。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};